B.acR=new A.aw("Teklif nas\u0131l veririm?",'Ke\u015ffet ekran\u0131ndan bir ilan\u0131 se\xe7in, "Teklif Ver" butonuna t\u0131klay\u0131n, fiyat\u0131n\u0131z\u0131 ve mesaj\u0131n\u0131z\u0131 girin. Teklif m\xfc\u015fteriye iletilir; kabul, ret veya pazarl\u0131k teklifi alabilirsiniz.')
B.acV=new A.aw("Kimlik do\u011frulama neden gerekli?","Mavi tik (\u2713) kazanmak i\xe7in kimlik foto\u011fraf\u0131n\u0131z\u0131 y\xfcklemeniz gerekir. Do\u011frulanm\u0131\u015f hesaplar daha fazla g\xfcven olu\u015fturur ve \xf6ne \xe7\u0131kar. Kimlik bilgileriniz \u015fifreli olarak saklan\u0131r, \xfc\xe7\xfcnc\xfc taraflarla payla\u015f\u0131lmaz.")
B.acH=new A.aw("Yeterlilik Belgesi nedir?",'Uzmanl\u0131k alan\u0131n\u0131za ait sertifika, diploma veya belgeleri y\xfckleyebilirsiniz. Onaylanan belgeler profilinizde "Belgelenmi\u015f Uzman" rozeti olarak g\xf6r\xfcn\xfcr.')
B.adg=new A.aw("Teklif fiyat\u0131 ba\u015fkas\u0131 g\xf6rebilir mi?","Hay\u0131r. Teklif tutar\u0131 yaln\u0131zca ilan sahibi ve teklifi veren ki\u015fi taraf\u0131ndan g\xf6r\xfclebilir. Di\u011fer kullan\u0131c\u0131lara tutar gizlenir.")
B.adc=new A.aw("\xd6deme nas\u0131l yap\u0131l\u0131r?","\xd6deme ilan sahibi ile usta aras\u0131nda do\u011frudan ger\xe7ekle\u015fir. Platform \u015fu an i\xe7in \xf6deme arac\u0131l\u0131k hizmeti sunmamaktad\u0131r. G\xfcvenli \xf6deme i\xe7in i\u015f tamamland\u0131ktan sonra \xf6deme yapman\u0131z\u0131 \xf6neririz.")
B.acL=new A.aw("De\u011ferlendirme nas\u0131l b\u0131rak\u0131r\u0131m?",'\u0130\u015f tamamland\u0131ktan sonra ilan detay ekran\u0131ndaki kabul edilmi\u015f teklif kart\u0131nda "De\u011ferlendir" butonuna t\u0131klay\u0131n. 1-5 y\u0131ld\u0131z ve yorum b\u0131rakabilirsiniz.')
B.acW=new A.aw("Hesab\u0131m\u0131 nas\u0131l silerim?","Hesap silme i\u015flemi i\xe7in destek@hizmet.app adresine e-posta g\xf6nderiniz. Talebiniz 5 i\u015f g\xfcn\xfc i\xe7inde i\u015fleme al\u0131n\u0131r.")
B.adk=new A.aw("Teklif verirken hata al\u0131yorum?","Token bakiyenizin yeterli oldu\u011fundan emin olun. Her teklif belirli miktarda token gerektirir. Sorun devam ederse destek ekibimizle ileti\u015fime ge\xe7in.")
